export const generateProductImage = (category, name, color = '#667eea') => {
  return `data:image/svg+xml;base64,${btoa(`
    <svg width="400" height="500" xmlns="http://www.w3.org/2000/svg">
      <rect width="400" height="500" fill="${color}"/>
      <text x="200" y="250" font-size="24" fill="#ffffff" text-anchor="middle" font-weight="bold">
        ${name}
      </text>
      <text x="200" y="280" font-size="16" fill="#ffffff" text-anchor="middle" opacity="0.7">
        ${category}
      </text>
    </svg>
  `)}`;
};
